WITH TicketUpdates AS (
    SELECT DISTINCT ticket_id, changed_by
    FROM ticket_history
)
SELECT COUNT(DISTINCT ticket_id) + COUNT(DISTINCT changed_by) AS overall_ticket_management_activity
FROM TicketUpdates;

SELECT COUNT(ticket_id) 
FROM tickets 
WHERE status_id = (SELECT status_id FROM statuses WHERE status_name = 'in progress');

SELECT p.project_id
FROM projects p
JOIN tickets t ON t.milestone_id IN (
  SELECT milestone_id FROM milestones WHERE project_id = p.project_id
) OR t.component_id IN (
  SELECT component_id FROM components WHERE project_id = p.project_id
)
WHERE p.end_date IS NULL OR p.end_date > CURRENT_DATE
GROUP BY p.project_id
HAVING COUNT(t.ticket_id) > 5;
